@import "tailwindcss";
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');

:root {
  /* Tennis Court Colors */
  --court-green: #228B22;
  --court-green-light: #32CD32;
  --court-green-dark: #006400;
  --tennis-ball: #CCFF00;
  --tennis-ball-dark: #9ACD32;

  /* Neutral Colors */
  --background: #ffffff;
  --background-secondary: #f8faf9;
  --foreground: #1a1a1a;
  --foreground-muted: #6b7280;
  --border: #e5e7eb;
  --border-muted: #f3f4f6;

  /* Semantic Colors */
  --success: var(--court-green);
  --warning: #f59e0b;
  --error: #ef4444;
  --info: #3b82f6;
}

@theme inline {
  /* Colors */
  --color-background: var(--background);
  --color-background-secondary: var(--background-secondary);
  --color-foreground: var(--foreground);
  --color-foreground-muted: var(--foreground-muted);
  --color-border: var(--border);
  --color-border-muted: var(--border-muted);

  /* Brand Colors */
  --color-primary: var(--court-green);
  --color-primary-light: var(--court-green-light);
  --color-primary-dark: var(--court-green-dark);
  --color-accent: var(--tennis-ball);
  --color-accent-dark: var(--tennis-ball-dark);

  /* Semantic Colors */
  --color-success: var(--success);
  --color-warning: var(--warning);
  --color-error: var(--error);
  --color-info: var(--info);

  /* Typography */
  --font-family-sans: 'Inter', system-ui, -apple-system, sans-serif;
  --font-family-mono: 'Fira Code', 'Monaco', 'Consolas', monospace;

  /* Spacing & Sizing */
  --radius: 0.5rem;
  --radius-lg: 0.75rem;
  --radius-xl: 1rem;

  /* Shadows */
  --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
  --shadow: 0 1px 3px 0 rgb(0 0 0 / 0.1), 0 1px 2px -1px rgb(0 0 0 / 0.1);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);
}

@media (prefers-color-scheme: dark) {
  :root {
    --background: #0a0a0a;
    --background-secondary: #111111;
    --foreground: #ededed;
    --foreground-muted: #9ca3af;
    --border: #374151;
    --border-muted: #1f2937;
  }
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-family-sans);
  font-feature-settings: 'rlig' 1, 'calt' 1;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Custom scrollbar */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: var(--background-secondary);
}

::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--foreground-muted);
}

/* Selection */
::selection {
  background-color: var(--tennis-ball);
  color: var(--foreground);
}

/* Focus styles */
*:focus-visible {
  outline: 2px solid var(--court-green);
  outline-offset: 2px;
}

