      .attr('x1', d => xScale(d))
      .attr('x2', d => xScale(d))
      .attr('y1', 0)
      .attr('y2', -innerHeight)
      .attr('stroke', '#e5e7eb')
      .attr('stroke-width', 1)
      .attr('opacity', 0.7);

    yAxisGrid.selectAll('line')
      .data(yScale.ticks(6))
      .enter()
      .append('line')
      .attr('x1', 0)
      .attr('x2', innerWidth)
      .attr('y1', d => yScale(d))
      .attr('y2', d => yScale(d))
      .attr('stroke', '#e5e7eb')
      .attr('stroke-width', 1)
      .attr('opacity', 0.7);

    // Create tooltip div
    const tooltip = d3.select('body').selectAll('.scatter-tooltip').data([null]);
    const tooltipEnter = tooltip.enter().append('div').attr('class', 'scatter-tooltip');
    const tooltipUpdate = tooltipEnter.merge(tooltip)
      .style('position', 'absolute')
      .style('visibility', 'hidden')
      .style('background', 'rgba(0, 0, 0, 0.8)')
      .style('color', 'white')
      .style('padding', '8px 12px')
      .style('border-radius', '6px')
      .style('font-size', '12px')
      .style('pointer-events', 'none')
      .style('z-index', '1000')
      .style('font-family', 'Inter, sans-serif');

    // Add data points
    const circles = g.selectAll('.data-point')
      .data(data)
      .enter()
      .append('circle')
      .attr('class', 'data-point')
      .attr('cx', d => xScale(d.x))
      .attr('cy', d => yScale(d.y))
      .attr('r', d => d.size || 6)
      .attr('fill', d => d.color || colorScale(d.brand))
      .attr('stroke', '#ffffff')
      .attr('stroke-width', 2)
      .attr('opacity', 0.8)
      .style('cursor', 'pointer')
      .style('transition', 'all 0.2s ease');

    // Add hover interactions
    circles
      .on('mouseover', function(event, d) {
        // Enlarge hovered point
        d3.select(this)
          .transition()
          .duration(200)
          .attr('r', (d.size || 6) + 3)
          .attr('stroke-width', 3);

        // Show tooltip
        tooltipUpdate
          .style('visibility', 'visible')
          .html(`
            <div style="font-weight: bold; margin-bottom: 4px;">${d.model}</div>
            <div>Brand: ${d.brand}</div>
            <div>${xLabel}: ${d.x.toFixed(2)}</div>
            <div>${yLabel}: ${d.y.toFixed(2)}</div>
          `);

        onPointHover?.(d);
      })
      .on('mousemove', function(event) {
        tooltipUpdate
          .style('top', (event.pageY - 10) + 'px')
          .style('left', (event.pageX + 10) + 'px');
      })
      .on('mouseout', function(event, d) {
        // Reset point size
        d3.select(this)
          .transition()
          .duration(200)
          .attr('r', d.size || 6)
          .attr('stroke-width', 2);

        // Hide tooltip
        tooltipUpdate.style('visibility', 'hidden');

        onPointHover?.(null);
      })
      .on('click', function(event, d) {
        onPointClick?.(d);
      });

    // Add axes
    const xAxis = d3.axisBottom(xScale)
      .tickSize(-innerHeight)
      .tickFormat(d3.format('.1f'));

    const yAxis = d3.axisLeft(yScale)
      .tickSize(-innerWidth)
      .tickFormat(d3.format('.1f'));

    g.append('g')
      .attr('class', 'x-axis')
      .attr('transform', `translate(0,${innerHeight})`)
      .call(xAxis)
      .selectAll('text')
      .style('font-family', 'Inter, sans-serif')
      .style('font-size', '12px')
      .style('fill', '#6b7280');

    g.append('g')
      .attr('class', 'y-axis')
      .call(yAxis)
      .selectAll('text')
      .style('font-family', 'Inter, sans-serif')
      .style('font-size', '12px')
      .style('fill', '#6b7280');

    // Style axis lines
    g.selectAll('.x-axis .domain, .y-axis .domain')
      .style('stroke', '#228B22')
      .style('stroke-width', 2);

    g.selectAll('.x-axis .tick line, .y-axis .tick line')
      .style('stroke', '#e5e7eb')
      .style('opacity', 0);

    // Add axis labels
    g.append('text')
      .attr('class', 'x-label')
      .attr('text-anchor', 'middle')
      .attr('x', innerWidth / 2)
      .attr('y', innerHeight + 50)
      .style('font-family', 'Inter, sans-serif')
      .style('font-size', '14px')
      .style('font-weight', '500')
      .style('fill', '#374151')
      .text(xLabel);

    g.append('text')
      .attr('class', 'y-label')
      .attr('text-anchor', 'middle')
      .attr('transform', 'rotate(-90)')
      .attr('x', -innerHeight / 2)
      .attr('y', -50)
      .style('font-family', 'Inter, sans-serif')
      .style('font-size', '14px')
      .style('font-weight', '500')
      .style('fill', '#374151')
      .text(yLabel);

    // Add title
    svg.append('text')
      .attr('class', 'chart-title')
      .attr('text-anchor', 'middle')
      .attr('x', dimensions.width / 2)
      .attr('y', 30)
      .style('font-family', 'Inter, sans-serif')
      .style('font-size', '18px')
      .style('font-weight', '600')
      .style('fill', '#1a1a1a')
      .text(title);

    setIsLoading(false);

    // Cleanup function
    return () => {
      d3.select('body').selectAll('.scatter-tooltip').remove();
    };
  }, [data, dimensions, xLabel, yLabel, title, onPointHover, onPointClick]);

  if (!data.length) {
    return (
      <Card className={`p-8 text-center ${className}`}>
        <p className="text-foreground-muted">No data available to display</p>
      </Card>
    );
  }

  return (
    <Card className={`relative ${className}`}>
      {isLoading && (
        <div className="absolute inset-0 flex items-center justify-center bg-white/80 z-10">
          <LoadingSpinner size="lg" />
        </div>
      )}
      <div ref={containerRef} className="w-full">
        <svg
          ref={svgRef}
          width={dimensions.width}
          height={dimensions.height}
          className="w-full h-auto"
        />
      </div>
    </Card>
  );
}

