        <div className="absolute bottom-20 right-1/3 w-5 h-5 bg-accent rounded-full animate-bounce opacity-25" style={{ animationDelay: '0.5s', animationDuration: '3.5s' }}></div>
      </div>

      {/* Header */}
      <header className="border-b border-border-muted relative z-10">
        <div className="container mx-auto px-4 py-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center shadow-lg">
                <span className="text-white font-bold text-lg">🎾</span>
              </div>
              <div>
                <h1 className="text-xl font-bold text-foreground">
                  Tennis Racquet Explorer
                </h1>
                <p className="text-sm text-foreground-muted">
                  Discover the intersection of feel and physics
                </p>
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* Hero Section */}
      <main className="container mx-auto px-4 py-12 relative z-10">
        <div className="max-w-4xl mx-auto text-center">
          <h2 className="text-4xl md:text-6xl font-bold text-foreground mb-6">
